// Cached Content Model
class CachedContent {
  final String key;
  final String data;
  final DateTime cachedAt;
  final Duration ttl;

  CachedContent({
    required this.key,
    required this.data,
    required this.cachedAt,
    this.ttl = const Duration(minutes: 30),
  });

  bool get isExpired => DateTime.now().isAfter(cachedAt.add(ttl));

  Map<String, dynamic> toJson() => {
        'key': key,
        'data': data,
        'cachedAt': cachedAt.toIso8601String(),
        'ttlMinutes': ttl.inMinutes,
      };

  factory CachedContent.fromJson(Map<String, dynamic> json) => CachedContent(
        key: json['key'] as String,
        data: json['data'] as String,
        cachedAt: DateTime.parse(json['cachedAt'] as String),
        ttl: Duration(minutes: json['ttlMinutes'] as int? ?? 30),
      );
}

// Secure Storage Manager - handles sensitive data
class SecureStorageManager {
  static const _storage = FlutterSecureStorage(
    aOptions: AndroidOptions(encryptedSharedPreferences: true),
    iOptions: IOSOptions(accessibility: KeychainAccessibility.first_unlock),
  );

  static const String _accessTokenKey = 'access_token';
  static const String _refreshTokenKey = 'refresh_token';
  static const String _tokenExpiryKey = 'token_expiry';

  // Auth Tokens
  Future<void> saveAccessToken(String token) async {
    await _storage.write(key: _accessTokenKey, value: token);
  }

  Future<String?> getAccessToken() async {
    return await _storage.read(key: _accessTokenKey);
  }

  Future<void> saveRefreshToken(String token) async {
    await _storage.write(key: _refreshTokenKey, value: token);
  }

  Future<String?> getRefreshToken() async {
    return await _storage.read(key: _refreshTokenKey);
  }

  Future<void> saveTokenExpiry(DateTime expiry) async {
    await _storage.write(
        key: _tokenExpiryKey, value: expiry.toIso8601String());
  }

  Future<DateTime?> getTokenExpiry() async {
    final value = await _storage.read(key: _tokenExpiryKey);
    return value != null ? DateTime.tryParse(value) : null;
  }

  Future<bool> isTokenExpired() async {
    final expiry = await getTokenExpiry();
    if (expiry == null) return true;
    return DateTime.now().isAfter(expiry);
  }

  Future<void> saveAuthTokens({
    required String accessToken,
    required String refreshToken,
    required DateTime expiry,
  }) async {
    await Future.wait([
      saveAccessToken(accessToken),
      saveRefreshToken(refreshToken),
      saveTokenExpiry(expiry),
    ]);
  }

  Future<void> clearAuthTokens() async {
    await Future.wait([
      _storage.delete(key: _accessTokenKey),
      _storage.delete(key: _refreshTokenKey),
      _storage.delete(key: _tokenExpiryKey),
    ]);
  }

  Future<void> clearAll() async {
    await _storage.deleteAll();
  }
}

