// Cache Manager - handles cached content and offline data
class CacheManager {
  static const String _cachePrefix = 'cache_';
  static const String _userProfileKey = 'user_profile';
  static const String _appConfigKey = 'app_config';
  static const String _cachedKeysRegistryKey = 'cached_keys_registry';

  SharedPreferences? _prefs;

  Future<SharedPreferences> get prefs async {
    _prefs ??= await SharedPreferences.getInstance();
    return _prefs!;
  }

  // User Profile Cache (non-sensitive profile display data)
  Future<void> cacheUserProfile(UserProfile profile) async {
    final p = await prefs;
    final updatedProfile = profile.copyWith(lastUpdated: DateTime.now());
    await p.setString(_userProfileKey, jsonEncode(updatedProfile.toJson()));
  }

  Future<UserProfile?> getCachedUserProfile() async {
    final p = await prefs;
    final data = p.getString(_userProfileKey);
    if (data == null) return null;
    try {
      return UserProfile.fromJson(jsonDecode(data) as Map<String, dynamic>);
    } catch (e) {
      debugPrint('Error parsing cached user profile: $e');
      await p.remove(_userProfileKey);
      return null;
    }
  }

  Future<void> clearUserProfile() async {
    final p = await prefs;
    await p.remove(_userProfileKey);
  }

  // App Configuration Cache
  Future<void> cacheAppConfig(AppConfig config) async {
    final p = await prefs;
    await p.setString(_appConfigKey, jsonEncode(config.toJson()));
  }

  Future<AppConfig?> getCachedAppConfig() async {
    final p = await prefs;
    final data = p.getString(_appConfigKey);
    if (data == null) return null;
    try {
      return AppConfig.fromJson(jsonDecode(data) as Map<String, dynamic>);
    } catch (e) {
      debugPrint('Error parsing cached app config: $e');
      await p.remove(_appConfigKey);
      return null;
    }
  }

  // Generic Content Cache with TTL
  Future<void> cacheContent(String key, String data,
      {Duration ttl = const Duration(minutes: 30)}) async {
    final p = await prefs;
    final cached = CachedContent(
      key: key,
      data: data,
      cachedAt: DateTime.now(),
      ttl: ttl,
    );
    await p.setString('$_cachePrefix$key', jsonEncode(cached.toJson()));
    await _registerCacheKey(key);
  }

  Future<String?> getCachedContent(String key) async {
    final p = await prefs;
    final raw = p.getString('$_cachePrefix$key');
    if (raw == null) return null;
    try {
      final cached =
          CachedContent.fromJson(jsonDecode(raw) as Map<String, dynamic>);
      if (cached.isExpired) {
        await removeCachedContent(key);
        return null;
      }
      return cached.data;
    } catch (e) {
      debugPrint('Error parsing cached content for key $key: $e');
      await p.remove('$_cachePrefix$key');
      return null;
    }
  }

  Future<void> removeCachedContent(String key) async {
    final p = await prefs;
    await p.remove('$_cachePrefix$key');
    await _unregisterCacheKey(key);
  }

  // Cache JSON objects
  Future<void> cacheJson(String key, Map<String, dynamic> json,
      {Duration ttl = const Duration(minutes: 30)}) async {
    await cacheContent(key, jsonEncode(json), ttl: ttl);
  }

  Future<Map<String, dynamic>?> getCachedJson(String key) async {
    final data = await getCachedContent(key);
    if (data == null) return null;
    try {
      return jsonDecode(data) as Map<String, dynamic>;
    } catch (e) {
      debugPrint('Error parsing cached JSON for key $key: $e');
      return null;
    }
  }

  // Cache List of JSON objects
  Future<void> cacheJsonList(String key, List<Map<String, dynamic>> jsonList,
      {Duration ttl = const Duration(minutes: 30)}) async {
    await cacheContent(key, jsonEncode(jsonList), ttl: ttl);
  }

  Future<List<Map<String, dynamic>>?> getCachedJsonList(String key) async {
    final data = await getCachedContent(key);
    if (data == null) return null;
    try {
      final list = jsonDecode(data) as List;
      return list.map((e) => Map<String, dynamic>.from(e as Map)).toList();
    } catch (e) {
      debugPrint('Error parsing cached JSON list for key $key: $e');
      return null;
    }
  }

  // Cache key registry for bulk operations
  Future<void> _registerCacheKey(String key) async {
    final p = await prefs;
    final keys = p.getStringList(_cachedKeysRegistryKey) ?? [];
    if (!keys.contains(key)) {
      keys.add(key);
      await p.setStringList(_cachedKeysRegistryKey, keys);
    }
  }

  Future<void> _unregisterCacheKey(String key) async {
    final p = await prefs;
    final keys = p.getStringList(_cachedKeysRegistryKey) ?? [];
    keys.remove(key);
    await p.setStringList(_cachedKeysRegistryKey, keys);
  }

  Future<List<String>> getAllCacheKeys() async {
    final p = await prefs;
    return p.getStringList(_cachedKeysRegistryKey) ?? [];
  }

  // Purge expired cache entries
  Future<int> purgeExpiredCache() async {
    final keys = await getAllCacheKeys();
    int purgedCount = 0;
    for (final key in keys) {
      final p = await prefs;
      final raw = p.getString('$_cachePrefix$key');
      if (raw == null) {
        await _unregisterCacheKey(key);
        purgedCount++;
        continue;
      }
      try {
        final cached =
            CachedContent.fromJson(jsonDecode(raw) as Map<String, dynamic>);
        if (cached.isExpired) {
          await removeCachedContent(key);
          purgedCount++;
        }
      } catch (e) {
        await removeCachedContent(key);
        purgedCount++;
      }
    }
    return purgedCount;
  }

  // Clear all cached content
  Future<void> clearAllCache() async {
    final keys = await getAllCacheKeys();
    final p = await prefs;
    for (final key in keys) {
      await p.remove('$_cachePrefix$key');
    }
    await p.remove(_cachedKeysRegistryKey);
    await p.remove(_userProfileKey);
    await p.remove(_appConfigKey);
  }

  // Get cache size info
  Future<Map<String, int>> getCacheStats() async {
    final keys = await getAllCacheKeys();
    int totalEntries = keys.length;
    int expiredEntries = 0;
    int totalSizeBytes = 0;

    final p = await prefs;
    for (final key in keys) {
      final raw = p.getString('$_cachePrefix$key');
      if (raw != null) {
        totalSizeBytes += raw.length * 2; // rough estimate in bytes
        try {
          final cached =
              CachedContent.fromJson(jsonDecode(raw) as Map<String, dynamic>);
          if (cached.isExpired) expiredEntries++;
        } catch (_) {
          expiredEntries++;
        }
      } else {
        expiredEntries++;
      }
    }

    return {
      'totalEntries': totalEntries,
      'expiredEntries': expiredEntries,
      'activeEntries': totalEntries - expiredEntries,
      'estimatedSizeBytes': totalSizeBytes,
    };
  }
}

// Main Local Storage Manager - unified interface
class LocalStorageManager {
  static LocalStorageManager? _instance;

  final SecureStorageManager secure;
  final PreferencesManager preferences;
  final CacheManager cache;

  LocalStorageManager._({
    required this.secure,
    required this.preferences,
    required this.cache,
  });

  factory LocalStorageManager() {
    _instance ??= LocalStorageManager._(
      secure: SecureStorageManager(),
      preferences: PreferencesManager(),
      cache: CacheManager(),
    );
    return _instance!;
  }

  // Convenience: Check if user is authenticated
  Future<bool> isAuthenticated() async {
    final token = await secure.getAccessToken();
    if (token == null) return false;
    final isExpired = await secure.isTokenExpired();
    return !isExpired;
  }

  // Convenience: Full login persistence
  Future<void> persistLogin({
    required String accessToken,
    required String refreshToken,
    required DateTime tokenExpiry,
    required UserProfile userProfile,
  }) async {
    await secure.saveAuthTokens(
      accessToken: accessToken,
      refreshToken: refreshToken,
      expiry: tokenExpiry,
    );
    await cache.cacheUserProfile(userProfile);
  }

  // Convenience: Full logout cleanup
  Future<void> logout({bool clearPreferences = false}) async {
    await secure.clearAuthTokens();
    await cache.clearUserProfile();
    await cache.clearAllCache();
    if (clearPreferences) {
      await preferences.clearAll();
    }
  }

  // Convenience: Get quick-access user data without network
  Future<Map<String, dynamic>?> getOfflineUserData() async {
    final profile = await cache.getCachedUserProfile();
    if (profile == null) return null;
    return {
      'profile': profile,
      'isAuthenticated': await isAuthenticated(),
    };
  }

  // Full reset
  Future<void> resetAll() async {
    await secure.clearAll();
    await preferences.clearAll();
    await cache.clearAllCache();
  }

  // Maintenance: run periodic cleanup
  Future<void> performMaintenance() async {
    final purged = await cache.purgeExpiredCache();
    debugPrint('LocalStorageManager: Purged $purged expired cache entries');
  }
}

