    tokenExpiry: DateTime.now().add(const Duration(hours: 1)),
    userProfile: UserProfile(
      id: 'user_123',
      name: 'John Doe',
      email: 'john@example.com',
      avatarUrl: 'https://example.com/avatar.jpg',
    ),
  );

  // Check auth status
  final isAuth = await storage.isAuthenticated();
  debugPrint('Is authenticated: $isAuth');

  // Get offline user data
  final userData = await storage.getOfflineUserData();
  debugPrint('Offline user data: $userData');

  // --- User Preferences ---
  await storage.preferences.setThemeMode('dark');
  await storage.preferences.setNotificationsEnabled(true);
  await storage.preferences.setFontSize(16.0);
  await storage.preferences.setLocale('en_US');
  await storage.preferences.setOnboardingComplete(true);
  await storage.preferences.setDataSaver(false);

