  // --- App Configuration Cache ---
  await storage.cache.cacheAppConfig(AppConfig(
    apiBaseUrl: 'https://api.example.com/v2',
    cacheExpirationMinutes: 60,
    maintenanceMode: false,
    minimumAppVersion: '2.0.0',
    featureFlags: {
      'dark_mode': true,
      'new_dashboard': false,
      'push_notifications': true,
    },
  ));

  final config = await storage.cache.getCachedAppConfig();
  debugPrint('API Base URL: ${config?.apiBaseUrl}');
  debugPrint('Feature flags: ${config?.featureFlags}');

  // --- Content Caching ---
  // Cache API responses for offline access
  await storage.cache.cacheJson(
    'feed_page_1',
    {
      'items': [
        {'id': 1, 'title': 'First Post'},
        {'id': 2, 'title': 'Second Post'},
      ],
      'page': 1,
      'totalPages': 10,
    },
    ttl: const Duration(minutes: 15),
  );

  final feedData = await storage.cache.getCachedJson('feed_page_1');
  debugPrint('Cached feed: $feedData');

  // Cache a list
  await storage.cache.cacheJsonList(
    'categories',
    [
      {'id': 'tech', 'name': 'Technology'},
      {'id': 'science', 'name': 'Science'},
      {'id': 'art', 'name': 'Art'},
    ],
    ttl: const Duration(hours: 24),
  );

  final categories = await storage.cache.getCachedJsonList('categories');
  debugPrint('Cached categories: $categories');

  // Cache raw string content
  await storage.cache.cacheContent(
    'terms_of_service',
    'These are the terms of service...',
    ttl: const Duration(days: 7),
  );

  // --- Cache Management ---
  final stats = await storage.cache.getCacheStats();
  debugPrint('Cache stats: $stats');

  // Purge expired entries
  await storage.performMaintenance();

  // --- Secure Token Access ---
  final accessToken = await storage.secure.getAccessToken();
  debugPrint('Access token available: ${accessToken != null}');

  final tokenExpired = await storage.secure.isTokenExpired();
  debugPrint('Token expired: $tokenExpired');

  // --- Logout ---
